// SQL: WHERE price > 10
db.books.find({ price: { $gt: 10 } })

// SQL: WHERE price >= 10 AND price <= 20
db.books.find({ price: { $gte: 10, $lte: 20 } })

// SQL: WHERE publishedYear != 2000
db.books.find({ publishedYear: { $ne: 2000 } })

// SQL: WHERE genre IN ('fiction', 'classic')
db.books.find({ genres: { $in: ['fiction', 'classic'] } })

// SQL: WHERE genre NOT IN ('fiction', 'classic')
db.books.find({ genres: { $nin: ['fiction', 'classic'] } })

// Implicit AND — fields in the same object are ANDed together
// SQL: WHERE price > 10 AND inStock = true
db.books.find({ price: { $gt: 10 }, inStock: true })

// Explicit $and — needed when same field appears twice
db.books.find({ $and: [
  { publishedYear: { $gt: 1980 } },
  { publishedYear: { $lt: 2010 } }
]})

// $or — SQL: WHERE genres = 'dystopia' OR price < 10
db.books.find({ $or: [
  { genres: 'dystopia' },
  { price: { $lt: 10 } }
]})

// $not — negate a condition
db.books.find({ price: { $not: { $gt: 15 } } })
// equivalent to: WHERE price <= 15 OR price IS NULL

// $nor — neither condition is true
db.books.find({ $nor: [
  { inStock: true },
  { price: { $lt: 10 } }
]})

// Find books where genres contains 'fiction'
// (MongoDB checks if 'fiction' is any element of the array)
db.books.find({ genres: 'fiction' })

// Find books where genres contains BOTH 'fiction' AND 'classic'
db.books.find({ genres: { $all: ['fiction', 'classic'] } })

// Find books where genres has exactly 2 elements
db.books.find({ genres: { $size: 2 } })

// $elemMatch — match on multiple conditions within a single array element
// (useful for arrays of objects)
db.orders.find({
  items: {
    $elemMatch: { quantity: { $gte: 2 }, unitPrice: { $gt: 12 } }
  }
})

// Access array by index — first genre is 'dystopia'
db.books.find({ 'genres.0': 'dystopia' })

// Check if a field exists (SQL: WHERE col IS NOT NULL)
db.books.find({ promoCode: { $exists: true } })
db.books.find({ promoCode: { $exists: false } })  // field missing entirely

// Check type — type number 2 = String, 16 = Int32, 8 = Boolean
db.books.find({ price: { $type: 'number' } })

// Regex — SQL: WHERE title LIKE '%the%' (case-insensitive)
db.books.find({ title: { $regex: /the/i } })
db.books.find({ title: { $regex: 'the', $options: 'i' } })  // same thing

// SQL: WHERE title LIKE 'The%'
db.books.find({ title: { $regex: /^The/ } })

// { promoCode: null } matches TWO cases:
//   1. Documents where promoCode field exists and is null
//   2. Documents where promoCode field is completely absent
db.books.find({ promoCode: null })  // returns both types

// { $exists: false } matches ONLY documents where the field is entirely missing
db.books.find({ promoCode: { $exists: false } })  // missing field only

// { $exists: true } matches documents where the field exists (even if null)
db.books.find({ promoCode: { $exists: true } })   // exists, any value including null

// To match ONLY documents where promoCode is explicitly null (not missing):
db.books.find({ promoCode: { $eq: null, $exists: true } })

// HIGH selectivity — an index on email is very useful because
// almost every email value is unique (1 doc out of millions)
db.users.find({ email: 'alice@example.com' })
// → index returns 1 document, very fast

// LOW selectivity — an index on inStock (only 2 values: true/false)
// if 80% of books are inStock:true, the index matches 80% of all docs
db.books.find({ inStock: true })
// → index may not help; full scan might be faster

// Find books that are NOT in stock AND NOT cheap (price >= 10)
db.books.find({ $nor: [
  { inStock: true },
  { price: { $lt: 10 } }
]})
// Both conditions must be false: not in stock, and price is not < 10
